sql:
SELECT * 
FROM funds 
ORDER BY fund_expense_ratio DESC;

SELECT fund_id
FROM funds
WHERE total_number_of_holdings_in_port = (
    SELECT MIN(total_number_of_holdings_in_port)
    FROM funds
);

SELECT f.*
FROM funds f
INNER JOIN users u ON u.role_id IN (
    SELECT role_id FROM user_roles
    WHERE can_access_financial_data = 1
);
